def chunks(values: list[int], size: int) -> list[list[int]]:
    if size <= 0:
        raise ValueError("size must be positive")
    return [values[index:index + size] for index in range(0, len(values), size)]

class Vocabulary:
    def __init__(self, tokens: list[str]) -> None:
        self.token_to_id = {token: index for index, token in enumerate(tokens)}

    def encode(self, token: str) -> int:
        return self.token_to_id[token]

@torch.no_grad()
def evaluate(model: torch.nn.Module, batches: list[Tensor]) -> float:
    model.eval()
    losses: list[float] = []
    for batch in batches:
        logits = model(batch[:, :-1])
        losses.append(float(logits.mean()))
    return sum(losses) / len(losses)

type ModelStatus = 'idle' | 'training' | 'complete' | 'error'

type StatusCardProps = Readonly<{
  status: ModelStatus
  step: number
}>

export function StatusCard({ status, step }: StatusCardProps) {
  return <p>Status: {status}, step: {step}</p>
}

export type ModelInfo = Readonly<{
