}

export async function fetchModelInfo(signal: AbortSignal): Promise<unknown> {
  const response = await fetch('/api/model', { signal })
  if (!response.ok) {
    throw new Error(`request failed: ${response.status}`)
  }
  return response.json()
}

import { useState } from 'react'

export function Counter() {
  const [count, setCount] = useState(0)
  return (
    <button type="button" onClick={() => setCount((current) => current + 1)}>
      Count: {count}
    </button>
  )
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

export function readName(value: unknown): string {
  if (!isRecord(value) || typeof value.name !== 'string') throw new Error('invalid name')
  return value.name
}

